import{_ as a,o as i,c as n,a as e}from"./chunks/framework.8tiMeCK-.js";const g=JSON.parse('{"title":"9.11  LTTng 与 Trace Compass：高层视角的上帝模式","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch09_11.md","filePath":"notes/linux_kernel_debugging/ch09_11.md","lastUpdated":null}'),t={name:"notes/linux_kernel_debugging/ch09_11.md"};function p(l,s,h,r,d,k){return i(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="_9-11-lttng-与-trace-compass-高层视角的上帝模式" tabindex="-1">9.11 LTTng 与 Trace Compass：高层视角的上帝模式 <a class="header-anchor" href="#_9-11-lttng-与-trace-compass-高层视角的上帝模式" aria-label="Permalink to &quot;9.11  LTTng 与 Trace Compass：高层视角的上帝模式&quot;">​</a></h1><h4 id="进场-换一种视角看内核" tabindex="-1">进场：换一种视角看内核 <a class="header-anchor" href="#进场-换一种视角看内核" aria-label="Permalink to &quot;进场：换一种视角看内核&quot;">​</a></h4><p>到现在为止，我们主要是在和 Ftrace 以及它的衍生品打交道。Ftrace 很棒，它是内核自带的，几乎零依赖，不仅能看还能改。但有时候，你需要的不只是一个「手电筒」，而是一套「全景监控系统」。</p><p>这就是 <strong>LTTng (Linux Trace Toolkit - next generation)</strong> 登场的时候。</p><p>LTTng 和我们之前聊的工具不太一样。Ftrace 像是一个精简的瑞士军刀，而 LTTng 则像是一台重型工业级 CT 扫描仪。它不仅盯着内核，还能同时盯着用户空间的应用和库，专门为多核并行系统和实时系统设计。如果你在调试那种「跑了十分钟才出现一次卡顿」的诡异问题，或者需要分析多核之间的复杂交互，LTTng 的能力会非常恐怖。</p><p>LTTng 的历史相当久远，最早版本（LTT）可以追溯到 2005 年，现在的 LTTng 是活跃维护的下一代版本。它开源，协议自由（LGPL/GPL/MIT 都有），而且在高性能计算领域名声在外。</p><p>但这套工具的文档也是出了名的详尽。由于篇幅限制，我没法把它的所有手册都搬运过来。如果你对「什么是 Tracing（跟踪）」以及它和「Profiling（性能分析）」的本质区别感兴趣，强烈建议去刷一遍 LTTng 官网的文档，那是真正的教科书级别。</p><h4 id="上号-lttng-的安装与快速上手" tabindex="-1">上号：LTTng 的安装与快速上手 <a class="header-anchor" href="#上号-lttng-的安装与快速上手" aria-label="Permalink to &quot;上号：LTTng 的安装与快速上手&quot;">​</a></h4><p>既然我们要在内核里用，第一步自然是安装。</p><p>如果你用的是 Ubuntu 20.04，不想折腾源码包，直接用 apt 就能搞定：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lttng-tools</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lttng-modules-dkms</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>⚠️ 仓库版本提醒</strong> 不过要注意，仓库里的版本通常不是最新的。在我写这段代码的时候，用这个方法装到的是 2.11 和 2.12 版本的模块，而官方最新的稳定版已经到了 2.13。大部分情况下这没问题，但如果你发现某些新特性没有，可能就是版本差了一代。</p><p>装好之后，建议先去 LTTng 官网把《Quick start guide》过一遍。虽然它能追踪用户空间，但作为一个内核调试的书，我们这里只关心 <strong>Kernel Tracing</strong>。</p><h4 id="核心流程-lttng-的五步走" tabindex="-1">核心流程：LTTng 的五步走 <a class="header-anchor" href="#核心流程-lttng-的五步走" aria-label="Permalink to &quot;核心流程：LTTng 的五步走&quot;">​</a></h4><p>用 LTTng 记录一次内核追踪会话，逻辑其实非常清晰。虽然它有很多参数，但核心流程只有五步（全程需要 root 权限）：</p><p><strong>第一步：建立会话</strong></p><p>我们需要告诉 LTTng：「我要开始干活了，数据存这里」。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lttng</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">session-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">/my_lttng_traces/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果不加 <code>--output</code> 参数，它默认会扔在 <code>~/lttng_traces/</code> 目录下。</p><p><strong>第二步：启用事件</strong></p><p>LTTng 的核心思想是「事件」。你需要明确告诉它你想抓什么。这里为了演示简单（也为了别把硬盘撑爆），我们开启<strong>所有</strong>内核事件：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lttng</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable-event</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --kernel</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --all</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>⚠️ 暴力开启的代价</strong> 这只是演示。在生产环境，<code>--all</code> 是个危险动作。所有的 syscall、所有的调度器事件、所有的网络包进出……全部都会被记录下来。如果是高负载服务器，日志文件增长的速度会让你怀疑人生。实际使用时，请务必指定具体的事件类或通道。</p><p><strong>第三步：开始记录</strong></p><p>准备好了？按开关。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lttng</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>现在，去干你想干的事。复现那个 bug，或者跑那个压力测试。</p><p><strong>第四步：停止记录</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lttng</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这一步其实不是必须的——因为下一步的 destroy 会自动停止它。但如果你想在同一次会话里分批次记录，stop 可以让你暂停一下。</p><p><strong>第五步：销毁会话</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lttng</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> destroy</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这里的「销毁」听起来有点吓人，但别担心——它只是销毁 LTTng 守护进程里的会话配置，<strong>不会删除</strong>你已经保存下来的原始 trace 数据。</p><p>最后，如果你想让非 root 用户也能看这些数据，记得改一下权限：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chown</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">whoami</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">whoami</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">~/my_lttng_traces</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h4 id="实战-再次追踪那个-ping-包" tabindex="-1">实战：再次追踪那个 Ping 包 <a class="header-anchor" href="#实战-再次追踪那个-ping-包" aria-label="Permalink to &quot;实战：再次追踪那个 Ping 包&quot;">​</a></h4><p>为了让你有个直观的感受，我写了一个简单的 Bash 脚本，把上面的步骤封装了一下。你可以在这里找到它：<code>ch9/lttng/lttng_trc.sh</code>。这个脚本只是为了让你的生活更轻松一点（我也只做了轻量测试，不保证在所有环境下都完美）。</p><p>它的用法很简单：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cd</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">lkd_sr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/ch9/lttng</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./lttng_trc.sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Usage:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lttng_trc.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> session-name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> program-to-trace-with-LTTng</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">0</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  1st</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> parameter:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> of</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> the</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> session</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  2nd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> parameter,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ...:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">If</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;0&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> is</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> passed,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> we</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> just</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> do</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> trace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> of</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> the</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> entire</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> system</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (all </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">kevents</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    else</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> we</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> do</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> trace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> of</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> the</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> particular</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> process</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (all </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">kevents</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">).</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Eg.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./lttng_trc.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ps1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ps</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -LA</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[NOTE: other stuff running _also_ gets traced (this is non</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">exclusive)].</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>让我们继续拿 <code>ping</code> 开刀。这几乎是我们的老朋友了：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./lttng_trc.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ping1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ping</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> packtpub.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>脚本会跑一圈，然后你会发现，除了屏幕输出，它还在 <code>/tmp</code> 目录下生成了一个压缩包（比如 <code>lttng_ping1_08Mar22_1104.tar.gz</code>）。这就是你的「黑匣子」记录，你可以把它拷贝到另一台机器上慢慢分析，完全不用在生产环境上挂着沉重的图形界面。</p><h4 id="命令行分析-babeltrace-的洪流" tabindex="-1">命令行分析：Babeltrace 的洪流 <a class="header-anchor" href="#命令行分析-babeltrace-的洪流" aria-label="Permalink to &quot;命令行分析：Babeltrace 的洪流&quot;">​</a></h4><p>拿到了数据，怎么看？</p><p>LTTng 自带了一个叫 <strong>Babeltrace 2</strong> 的命令行工具。顾名思义，它是巴别塔的翻译——把 LTTng 那种二进制的、高效的 CTF（Common Trace Format）格式，翻译成人类能读的文本。</p><p>你可以参考官方文档来学习它的详细用法。但我必须给你打个预防针：<strong>输出量是惊人的</strong>。</p><p>刚才那个单次 ping 的操作，如果用 Babeltrace 2 导出成文本，生成了 <strong>超过 123,000 行</strong>的信息。</p><p>这就像是你把整座大楼的水管图纸铺满了整个足球场。虽然信息全在那里，但靠肉眼看这些文本流，眼睛会瞎掉的。这就是为什么我们需要图形界面。</p><h4 id="图形化可视化-trace-compass-的上帝视角" tabindex="-1">图形化可视化：Trace Compass 的上帝视角 <a class="header-anchor" href="#图形化可视化-trace-compass-的上帝视角" aria-label="Permalink to &quot;图形化可视化：Trace Compass 的上帝视角&quot;">​</a></h4><p>如果用命令行是「在地面上找管道」，那 <strong>Trace Compass</strong> 就是让你「坐卫星看全貌」。</p><p>Trace Compass 是基于 Eclipse 的一个项目（Eclipse RCP），也是 LTTng 官方推荐的图形化查看器。它的安装非常简单，去官网下载解压即可。</p><p>安装好后，启动 Trace Compass，菜单栏选择 <code>File | Open Trace...</code>，然后选中你刚才保存 trace 数据的目录。它会自动解析，然后给你呈现一个极其专业的控制台。</p><p>屏幕会被分成好几块。最上面是一个巨大的时间轴，中间是事件列表，下面是详细信息。一开始看可能会有点晕，因为它确实提供了太多维度的信息了。</p><p><strong>精准定位：过滤的艺术</strong></p><p>面对大海一样的数据，我们要学会钓鱼。在刚才那个 ping 的例子里，为了找到那一瞬间的网络包传输，我做了两件事：</p><ol><li><strong>锁定 CPU</strong>：我知道 ping 刚好在 CPU 6 上跑了（可能是因为调度器刚好把它扔那了），所以在 CPU 列的搜索框里输入 <code>6</code>。</li><li><strong>锁定事件</strong>：在 Contents 列输入 <code>icmp</code>。</li></ol><p>Trace Compass 会立刻帮你把噪音过滤掉，只剩下你关心的那根针。</p><p>在上面的截图中，你可以看到一个高亮的行：<code>net_dev_queue</code>。这代表着网络设备准备发送队列。右键点击这一行，<code>Copy to Clipboard</code>，贴出来你会看到一段非常详细的文本：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Timestamp    Channel      CPU  Event type     Contents   TID    Prio     PID      Source</span></span>
<span class="line"><span>18:39:11.274 970 channel0_6 6   net_dev_queue     </span></span>
<span class="line"><span>skbaddr=0xffff8a4c30fb5c00, len=98, name=eno2, network_header_</span></span>
<span class="line"><span>type=_ipv4, network_header=ipv4=[version=4, ihl=5, tos=0, </span></span>
<span class="line"><span>tot_len=84, id=0x2950, frag_off=16384, ttl=64, protocol=_</span></span>
<span class="line"><span>icmp, checksum=0xe6db, saddr_padding=[], saddr=[192, 168, 1, </span></span>
<span class="line"><span>16], daddr_padding=[], daddr=[104, 22, 0, 175], transport_</span></span>
<span class="line"><span>header_type=_icmp, transport_header=icmp=[type=8, code=0, </span></span>
<span class="line"><span>checksum=393, gateway=720897]]  3932722  20  3932722</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>这种细节，对于一个网络驱动开发者来说，就是金矿。你能看到 skb 的地址、包长、网卡名字，甚至是 IPv4 头里的每一个 bit 和 ICMP 的 payload。这就是运行时参数的价值。</p><h4 id="颜色的力量-一眼看懂系统状态" tabindex="-1">颜色的力量：一眼看懂系统状态 <a class="header-anchor" href="#颜色的力量-一眼看懂系统状态" aria-label="Permalink to &quot;颜色的力量：一眼看懂系统状态&quot;">​</a></h4><p>Trace Compass 最强的地方在于它的<strong>颜色编码</strong>。</p><p>它在时间轴上把进程的状态涂上了不同的颜色。你不需要读 log，只要看图：</p><ul><li><strong>蓝色</strong>：系统调用。</li><li><strong>绿色</strong>：用户空间代码正在跑。</li><li><strong>黄色</strong>：正在 blocked，比如等待 I/O。</li></ul><p>看回刚才那个截图，最左侧 ping 进程的起始位置是<strong>褐色</strong>。鼠标放上去一看，原来是 <code>sched_switch</code>，它在等 CPU 调度（非阻塞等待）。而最右侧的那一长条<strong>柠檬黄</strong>，则是它在阻塞等待 I/O（具体是 <code>power_cpu_idle</code> 事件，睡了 14.6 微秒）。</p><p>这种可视化，能让你瞬间理解系统的「呼吸节奏」。</p><h4 id="没有银弹-工具的选择与妥协" tabindex="-1">没有银弹：工具的选择与妥协 <a class="header-anchor" href="#没有银弹-工具的选择与妥协" aria-label="Permalink to &quot;没有银弹：工具的选择与妥协&quot;">​</a></h4><p>写到这儿，本章关于内核追踪的旅程就要告一段落了。</p><p>我们见识了 Ftrace 这个轻量级的忍者，玩了 trace-cmd 和 KernelShark 这对黄金搭档，又体验了 perf-tools 脚本的便捷，最后还在 LTTng 和 Trace Compass 的宏大图景里遨游了一圈。</p><p>你会发现一个事实：<strong>没有完美的工具</strong>。</p><ul><li>Trace Compass 的可视化很棒，一眼就能看出系统在干什么，但它在展示上下文细节（比如具体的延迟中断标志、抢占深度）这方面，就不如 KernelShark（以及背后的 Ftrace latency format）来得细腻。</li><li>Ftrace 什么都有，甚至能在内核崩了的时候帮你把内存里的 buffer 打出来（<code>ftrace_dump_on_oops</code>），但它在处理海量多核数据时的易用性，又不如 LTTng。</li></ul><p>早在 1975 年，Fred Brooks 就在《人月神话》里告诉过我们：<strong>没有银弹</strong>。</p><p>这就是为什么你需要把所有这些工具都装进你的工具箱里。在不同的场景下，针对不同的问题，选择最锋利的那把刀。</p><p>下一章，我们要面对一个更沉重的话题：<strong>Kernel Panic</strong>。别慌，有了今天的调试利器，哪怕是内核崩溃，我们也能从尸体里读出点东西来。</p><hr><h3 id="本章回响" tabindex="-1">本章回响 <a class="header-anchor" href="#本章回响" aria-label="Permalink to &quot;本章回响&quot;">​</a></h3><p>现在，让我们回到本章开头埋下的那个伏笔。</p><p>还记得吗，我们一开始就在纠结：为什么内核开发者需要这种「显微镜」级别的能力？</p><p>现在答案很清楚了：因为现代系统太复杂了。</p><p>当你的代码运行在成千上万行内核代码、几十个并发进程、无数个中断上下文的交织中时，「直觉」是最不可靠的东西。只有 Tracing（跟踪）能把这种混沌的动态过程，凝固成可视化的、可分析的数据。</p><p>无论是通过 <code>trace_pipe</code> 看着实时数据流过屏幕，还是在 Trace Compass 里拖动时间轴，你其实都是在做同一件事——<strong>消除不确定性</strong>。这正是系统级调试的本质。</p><p>下一章，当屏幕变成红色，当 <code>/dev/kmsg</code> 里抛出 <code>Oops</code> 和 <code>Stack dump</code>，不要惊慌。那是系统在向你求救，而我们今天学到的这些工具，就是你破译求救信号的密码本。</p>`,82)])])}const c=a(t,[["render",p]]);export{g as __pageData,c as default};
